```
for (let x = 0; x < 3; ++x) {
    x = ((x) => (setTimeout(() => x++), x))(x);
    if (condition()) break;
    x = ((x) => (setTimeout(() => x++), x))(x);
}
```

Or if we really want:
```
for (var x = 0; x < 3; ++x) {
    let y = x;
    setTimeout(() => y++));
    if (condition()) break;
    setTimeout(() => y++);
    x = y;
}
```

